public void initOptions(CompilerOptions options) {
  this.options = options;
  if (this.errorManager == null) {
    if (this.outStream == null) {
      this.setErrorManager(new LoggerErrorManager(this.createMessageFormatter(), this.logger));
    } else {
      PrintStreamErrorManager printer = new PrintStreamErrorManager(this.createMessageFormatter(), this.outStream); printer.setSummaryDetailLevel(this.options.summaryDetailLevel);
      this.setErrorManager(printer);
    }
  }
  // DiagnosticGroups override the plain checkTypes option.
  if (this.options.enables(DiagnosticGroups.CHECK_TYPES)) {
    this.options.checkTypes = true;
  } else if (this.options.disables(DiagnosticGroups.CHECK_TYPES)) {
    this.options.checkTypes = false;
  } else if (!this.options.checkTypes) {
    // If DiagnosticGroups did not override the plain checkTypes option, and checkTypes is enabled, then turn off the parser type warnings.
    this.options.setWarningLevel(DiagnosticGroup.forType(RhinoErrorReporter.TYPE_PARSE_ERROR), CheckLevel.OFF);
  }

  if (this.options.checkGlobalThisLevel.isOn()) {
    this.options.setWarningLevel(DiagnosticGroups.GLOBAL_THIS,this.options.checkGlobalThisLevel);
  }

  // Initialize the warnings guard.
  List<WarningsGuard> guards = Lists.newArrayList();
  guards.add(new SuppressDocWarningsGuard(getDiagnosticGroups().getRegisteredGroups()));
  guards.add(this.options.getWarningsGuard());

  // All passes must run the variable check. This synthesizes variables later so that the compiler doesn't crash. It also checks the externs file for validity. If you don't want to warn about missing variable declarations, we shut that specific error off.
  if (this.options.checkSymbols && (this.warningsGuard == null || !this.warningsGuard.disables(DiagnosticGroups.CHECK_VARIABLES))) {
    guards.add(new DiagnosticGroupWarningsGuard(DiagnosticGroups.CHECK_VARIABLES, CheckLevel.OFF));
  }

  this.warningsGuard = new ComposeWarningsGuard(guards);
}
